import fs from"fs-promise";import Promise from"bluebird";import path from"path";import untildify from"untildify";import{biomeLocalName,biomeFolderName}from"./constants";const lookFor={"package.json":e=>{let o=JSON.parse(e);return o?o.name:null},"setup.py":e=>{let o=e.match(/name[ ]+=[ ]+['"](.+)['"]/);return o?o[1]:null}};function getProjectName(){let e=[];for(let t in lookFor)e.push(o(path.join(process.cwd(),t),lookFor[t])),console.log(path.join(process.cwd(),t));function o(e,o){return fs.readFile(e).then(o)}return Promise.any(e)}export default function init(e){if("string"!=typeof e)return getProjectName().then(init);if(0!==e.trim().length){let o=path.join(process.cwd(),biomeLocalName());return fs.writeFile(o,JSON.stringify({name:e},null,2)).then(o=>{let t=path.join(biomeFolderName(),`${e}.json`);return fs.writeFile(t,"{}").then(o=>e)})}console.error("No project name was specified or found. Please specify one manually.")}